$(errorCatched(async () => {

  const ID  = 'th-orb-v2';
  let pdoc, pwin;
  // ── 安全获取 parent ───────────────────────────────────────
  // iOS WKWebView 里 parent.document 可能跨域报错，统一 fallback
  try {
    pdoc = (parent && parent.document) ? parent.document : document;
    pwin = (parent && parent.window)   ? parent.window   : window;
  } catch (e) {
    pdoc = document;
    pwin = window;
  }

  // ── 防重复 ───────────────────────────────────────────────
  pdoc.getElementById(ID)?.remove();
  pdoc.getElementById(`${ID}-style`)?.remove();

  // ── 读取保存的位置 ───────────────────────────────────────
  const isMobile = pwin.innerWidth <= 768;
  let pos = isMobile
    ? { x: pwin.innerWidth - 60, y: pwin.innerHeight - 120 }
    : { x: 40, y: 160 };
  try {
    const r = getVariables({ type: 'global' })?.['orbV2_pos'];
    if (r) {
      const saved = JSON.parse(r);
      saved.x = Math.max(4, Math.min(saved.x, pwin.innerWidth  - 56));
      saved.y = Math.max(4, Math.min(saved.y, pwin.innerHeight - 56));
      Object.assign(pos, saved);
    }
  } catch (_) {}

  // ── 样式 ─────────────────────────────────────────────────
  const style = pdoc.createElement('style');
  style.id = `${ID}-style`;
  style.textContent = `
    #${ID} {
      position: fixed !important;
      z-index: 2147483647 !important;
      width: 52px;
      height: 52px;
      font-family: 'Microsoft YaHei', 'PingFang SC', sans-serif;
      user-select: none;
      -webkit-user-select: none;
    }

    /* ── 圆球按钮 ── */
    #${ID} .orb {
      position: absolute;
      top: 0; left: 0;
      width: 52px; height: 52px;
      border-radius: 50%;
      cursor: pointer;
      z-index: 2;
      touch-action: none;
      background:
        radial-gradient(circle at 35% 32%, rgba(200,160,255,0.18) 0%, transparent 60%),
        radial-gradient(circle at 68% 72%, rgba(100,60,200,0.22) 0%, transparent 55%),
        linear-gradient(145deg, rgba(30,18,52,0.95) 0%, rgba(14,10,28,0.98) 100%);
      border: 1.5px solid rgba(180,130,255,0.38);
      box-shadow:
        0 0 0 1px rgba(0,0,0,0.6),
        0 0 18px rgba(140,80,255,0.38),
        0 0 40px rgba(100,40,200,0.18),
        inset 0 1px 0 rgba(255,255,255,0.12),
        inset 0 -1px 0 rgba(0,0,0,0.4);
      display: flex;
      align-items: center;
      justify-content: center;
      transition: box-shadow 0.3s ease, border-color 0.3s ease;
      -webkit-tap-highlight-color: transparent;
    }
    #${ID} .orb:hover {
      border-color: rgba(210,160,255,0.6);
      box-shadow:
        0 0 0 1px rgba(0,0,0,0.6),
        0 0 28px rgba(180,100,255,0.6),
        0 0 60px rgba(120,50,240,0.28),
        inset 0 1px 0 rgba(255,255,255,0.15),
        inset 0 -1px 0 rgba(0,0,0,0.4);
    }
    #${ID} .orb-icon {
      font-size: 20px;
      line-height: 1;
      color: #ffffff;
      transition: transform 0.55s cubic-bezier(0.34,1.56,0.64,1);
      filter: drop-shadow(0 0 6px rgba(200,150,255,0.8));
      pointer-events: none;
    }
    #${ID}.open .orb-icon { transform: rotate(360deg); }

    /* 装饰旋转环 */
    #${ID} .orb-ring {
      position: absolute;
      top: -5px; left: -5px;
      width: 62px; height: 62px;
      border-radius: 50%;
      border: 1px solid transparent;
      border-top-color: rgba(200,150,255,0.55);
      border-right-color: rgba(150,80,255,0.22);
      pointer-events: none;
      opacity: 0;
      transition: opacity 0.3s;
    }
    @keyframes orb-spin { to { transform: rotate(360deg); } }
    #${ID}.open .orb-ring {
      opacity: 1;
      animation: orb-spin 3s linear infinite;
    }
    @keyframes orb-pulse {
      0%,100% { box-shadow: 0 0 0 1px rgba(0,0,0,0.6), 0 0 18px rgba(140,80,255,0.38), 0 0 40px rgba(100,40,200,0.18), inset 0 1px 0 rgba(255,255,255,0.12), inset 0 -1px 0 rgba(0,0,0,0.4); }
      50%      { box-shadow: 0 0 0 1px rgba(0,0,0,0.6), 0 0 28px rgba(160,90,255,0.55), 0 0 55px rgba(110,45,210,0.26), inset 0 1px 0 rgba(255,255,255,0.12), inset 0 -1px 0 rgba(0,0,0,0.4); }
    }
    #${ID}:not(.open) .orb { animation: orb-pulse 3s ease-in-out infinite; }

    /* ── 下拉菜单 ── */
    #${ID} .menu {
      position: absolute;
      width: 220px;
      max-width: calc(100vw - 16px);
      pointer-events: none;
      transform: scale(0.88) translateY(-8px);
      opacity: 0;
      transition:
        transform 0.28s cubic-bezier(0.34,1.3,0.64,1),
        opacity   0.22s ease;
      touch-action: auto;
    }
    #${ID}.open .menu {
      pointer-events: all;
      transform: scale(1) translateY(0);
      opacity: 1;
    }
    #${ID}.open-up .menu { transform: scale(0.88) translateY(8px); }
    #${ID}.open.open-up .menu { transform: scale(1) translateY(0); }

    #${ID} .menu-shell {
      background: linear-gradient(150deg, rgba(14,10,26,0.96) 0%, rgba(22,16,38,0.94) 100%);
      border: 1px solid rgba(170,120,255,0.24);
      border-radius: 12px;
      backdrop-filter: blur(28px) saturate(160%);
      -webkit-backdrop-filter: blur(28px) saturate(160%);
      overflow: hidden;
      box-shadow:
        inset 0 1px 0 rgba(255,255,255,0.07),
        0 0 0 1px rgba(0,0,0,0.5),
        0 8px 32px rgba(80,30,180,0.22),
        0 2px 8px rgba(0,0,0,0.5);
    }
    #${ID} .menu-head {
      display: flex;
      align-items: center;
      gap: 7px;
      padding: 9px 12px 8px;
      background: linear-gradient(90deg, rgba(100,50,200,0.3) 0%, rgba(50,25,100,0.16) 100%);
      border-bottom: 1px solid rgba(170,120,255,0.13);
      border-radius: 12px 12px 0 0;
      cursor: grab;
      touch-action: none;
      flex-shrink: 0;
    }
    #${ID} .menu-head:active { cursor: grabbing; }
    #${ID} .menu-gem {
      width: 8px; height: 8px;
      border-radius: 50%;
      background: radial-gradient(circle at 30% 30%, #e9d5ff, #7c3aed);
      box-shadow: 0 0 8px rgba(167,139,250,0.7);
      flex-shrink: 0;
    }
    #${ID} .menu-title {
      font-size: 13px;
      font-weight: 700;
      letter-spacing: 0.16em;
      color: rgba(255,255,255,0.95);
      text-shadow: 0 0 12px rgba(167,139,250,0.4);
      flex: 1;
    }
    #${ID} .menu-close {
      width: 28px; height: 28px;
      border-radius: 5px;
      border: 1px solid rgba(170,120,255,0.18);
      background: rgba(255,255,255,0.04);
      color: rgba(230,210,255,0.85);
      cursor: pointer;
      display: flex; align-items: center; justify-content: center;
      font-size: 14px;
      transition: all 0.18s;
      flex-shrink: 0;
      padding: 0;
      -webkit-tap-highlight-color: transparent;
      touch-action: manipulation;
    }
    #${ID} .menu-close:hover {
      background: rgba(200,50,50,0.22);
      color: #fca5a5;
      border-color: rgba(239,68,68,0.4);
    }
    #${ID} .menu-list {
      padding: 6px;
      display: flex;
      flex-direction: column;
      gap: 3px;
      overflow-y: auto;
      overflow-x: hidden;
      max-height: 60vh;
      touch-action: pan-y;
      scrollbar-width: thin;
      scrollbar-color: rgba(170,120,255,0.3) transparent;
      /* iOS 惯性滚动 */
      -webkit-overflow-scrolling: touch;
    }
    #${ID} .menu-list::-webkit-scrollbar { width: 4px; }
    #${ID} .menu-list::-webkit-scrollbar-track { background: transparent; }
    #${ID} .menu-list::-webkit-scrollbar-thumb {
      background: rgba(170,120,255,0.3);
      border-radius: 4px;
    }
    #${ID} .menu-item {
      display: flex;
      align-items: center;
      gap: 9px;
      padding: 11px 11px;
      border-radius: 10px;
      border: 1px solid rgba(170,120,255,0.22);
      cursor: pointer;
      transition: all 0.16s ease;
      background: rgba(20,14,36,0.6);
      margin: 2px 6px;
      -webkit-tap-highlight-color: transparent;
      touch-action: manipulation;
    }
    #${ID} .menu-item:hover {
      background: rgba(120,70,220,0.18);
      border-color: rgba(170,120,255,0.45);
    }
    #${ID} .menu-item:active {
      background: rgba(120,70,220,0.3);
      transform: scale(0.98);
    }
    #${ID} .sexy-title {
      font-size: 13px;
      font-weight: 700;
      letter-spacing: 0.12em;
      color: rgba(255,255,255,0.85);
      padding: 8px 12px 3px;
      text-shadow: 0 0 10px rgba(180,120,255,0.3);
    }
    #${ID} .sexy-group {
      margin: 2px 6px;
      display: flex;
      border-radius: 10px;
      border: 1px solid rgba(170,120,255,0.22);
      overflow: hidden;
      background: rgba(20,14,36,0.6);
      height: 52px;
      flex-shrink: 0;
    }
    #${ID} #${ID}-paraphrase-group { height: 34px; }
    #${ID} #${ID}-talk-group { height: 34px; }
    #${ID} #${ID}-word-group  { height: 34px; }
    #${ID} #${ID}-robtalk-group { height: 34px; }
    #${ID} .sexy-seg {
      flex: 1;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      gap: 3px;
      cursor: pointer;
      position: relative;
      transition: background 0.18s, box-shadow 0.18s;
      background: transparent;
      -webkit-tap-highlight-color: transparent;
      touch-action: manipulation;
    }
    #${ID} .sexy-seg + .sexy-seg { border-left: 1px solid rgba(170,120,255,0.15); }
    #${ID} .sexy-seg:hover { background: rgba(120,70,220,0.15); }
    #${ID} .sexy-seg:active { transform: scale(0.97); }
    #${ID} .sexy-seg-label {
      font-size: 12px;
      color: rgba(255,255,255,0.82);
      letter-spacing: 0.02em;
      text-align: center;
      line-height: 1.3;
      transition: color 0.18s, text-shadow 0.18s;
      pointer-events: none;
    }
    #${ID} .sexy-seg-desc {
      font-size: 10px;
      color: rgba(210,190,255,0.55);
      text-align: center;
      line-height: 1.2;
      transition: color 0.18s;
      pointer-events: none;
    }
    #${ID} .sexy-seg.is-on {
      background: rgba(220,50,110,0.18);
      box-shadow: inset 0 0 18px rgba(255,60,130,0.1);
    }
    #${ID} .sexy-seg.is-on .sexy-seg-label {
      color: rgba(255,190,220,0.98);
      text-shadow: 0 0 8px rgba(255,90,155,0.55);
    }
    #${ID} .sexy-seg.is-on .sexy-seg-desc { color: rgba(255,160,200,0.55); }
    #${ID} .sexy-seg.is-on::after {
      content: '';
      position: absolute;
      bottom: 0; left: 10%; right: 10%;
      height: 2px;
      border-radius: 2px;
      background: linear-gradient(90deg, transparent, rgba(255,80,150,0.7), transparent);
    }
    #${ID} .menu-item-text {
      font-size: 14px;
      color: rgba(255,255,255,0.92);
      letter-spacing: 0.04em;
      line-height: 1.3;
      transition: color 0.2s, text-shadow 0.2s;
      pointer-events: none;
    }
    #${ID} .menu-item-desc {
      font-size: 11px;
      color: rgba(210,185,255,0.6);
      margin-top: 1px;
      transition: color 0.2s;
      pointer-events: none;
    }
    #${ID} .menu-hr {
      height: 1px;
      margin: 2px 6px;
      background: linear-gradient(90deg, transparent, rgba(170,120,255,0.18) 30%, rgba(170,120,255,0.18) 70%, transparent);
    }
    #${ID} .feat-grid {
      margin: 2px 6px;
      display: grid;
      gap: 5px;
      flex-shrink: 0;
    }
    #${ID} .feat-grid-3 { grid-template-columns: repeat(3, 1fr); }
    #${ID} .feat-grid-2 { grid-template-columns: repeat(2, 1fr); }
    #${ID} .feat-grid-1 { grid-template-columns: 1fr; }
    #${ID} .feat-grid-2 .feat-btn:only-child { grid-column: 1 / -1; }
    #${ID} .feat-btn {
      font-size: 11px;
      font-weight: 600;
      color: rgba(255,255,255,0.75);
      background: rgba(20,14,36,0.6);
      border: 1px solid rgba(170,120,255,0.22);
      border-radius: 8px;
      padding: 10px 4px;
      cursor: pointer;
      transition: all 0.16s ease;
      white-space: normal;
      word-break: break-all;
      text-align: center;
      line-height: 1.3;
      -webkit-tap-highlight-color: transparent;
      touch-action: manipulation;
    }
    #${ID} .feat-btn:hover {
      background: rgba(120,70,220,0.18);
      border-color: rgba(170,120,255,0.45);
    }
    #${ID} .feat-btn:active { transform: scale(0.96); }
    #${ID} .feat-btn.is-on {
      background: rgba(220,50,110,0.18);
      border-color: rgba(255,90,155,0.55);
      color: rgba(255,185,215,0.98);
      box-shadow: 0 0 8px rgba(255,60,130,0.25);
      text-shadow: 0 0 6px rgba(255,90,155,0.5);
    }
    #${ID} .feat-btn.disabled {
      opacity: 0.35;
      cursor: default;
      pointer-events: none;
    }
    #${ID} .menu-foot {
      padding: 5px 12px;
      font-size: 10px;
      letter-spacing: 0.1em;
      color: rgba(170,130,255,0.25);
      text-align: right;
      border-top: 1px solid rgba(170,120,255,0.07);
      border-radius: 0 0 12px 12px;
      flex-shrink: 0;
    }
    #${ID} .toggle-led {
      width: 8px; height: 8px;
      border-radius: 50%;
      flex-shrink: 0;
      background: rgba(90,70,110,0.5);
      border: 1px solid rgba(160,110,200,0.22);
      transition: all 0.25s ease;
      margin-left: auto;
      pointer-events: none;
    }
    #${ID} .menu-item-toggle.is-on .toggle-led {
      background: radial-gradient(circle at 38% 32%, #ffb3d4, #e0185e);
      box-shadow: 0 0 7px rgba(255,60,130,0.9), 0 0 16px rgba(255,60,130,0.45);
      border-color: rgba(255,130,175,0.7);
    }
    #${ID} .menu-item-toggle {
      display: flex;
      align-items: center;
      gap: 9px;
      padding: 11px 11px;
      border-radius: 10px;
      border: 1px solid rgba(170,120,255,0.22);
      cursor: pointer;
      transition: all 0.2s ease;
      background: rgba(20,14,36,0.6);
      margin: 2px 6px;
      -webkit-tap-highlight-color: transparent;
      touch-action: manipulation;
    }
    #${ID} .menu-item-toggle:hover {
      background: rgba(120,70,220,0.18);
      border-color: rgba(170,120,255,0.45);
    }
    #${ID} .menu-item-toggle.is-on {
      background: rgba(220,50,110,0.14);
      border-color: rgba(255,90,155,0.38);
    }
    #${ID} .menu-item-toggle.is-on .menu-item-text {
      color: rgba(255,185,215,0.96);
      text-shadow: 0 0 8px rgba(255,90,155,0.5);
    }
    #${ID} .pace-label {
      text-align: center;
      line-height: 1.45;
    }
    @keyframes orb-in {
      from { opacity:0; transform: scale(0.75); }
      to   { opacity:1; transform: scale(1); }
    }
    #${ID} { animation: orb-in 0.3s cubic-bezier(0.34,1.3,0.64,1) both; }
  `;
  pdoc.head.appendChild(style);

  // ── DOM ──────────────────────────────────────────────────
  const root = pdoc.createElement('div');
  root.id = ID;
  root.style.left = pos.x + 'px';
  root.style.top  = pos.y + 'px';

  root.innerHTML = `
    <div class="orb-ring"></div>
    <div class="orb" id="${ID}-orb">
      <span class="orb-icon">✦</span>
    </div>
    <div class="menu" id="${ID}-menu">
      <div class="menu-shell">
        <div class="menu-head" id="${ID}-head">
          <div class="menu-gem"></div>
          <div class="menu-title">TGbreak</div>
          <button class="menu-close" id="${ID}-close">✕</button>
        </div>
        <div class="menu-list">
          <div class="sexy-title">色色程度</div>
          <div class="sexy-group">
            <div class="sexy-seg" id="${ID}-item-sexy-l">
              <div class="sexy-seg-label">轻度</div>
              <div class="sexy-seg-desc">瑟瑟描述</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-sexy-m">
              <div class="sexy-seg-label">中度</div>
              <div class="sexy-seg-desc">够用了</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-sexy-h">
              <div class="sexy-seg-label">重度</div>
              <div class="sexy-seg-desc">记得关掉</div>
            </div>
          </div>
          <div class="sexy-title">可抢话设置</div>
          <div class="feat-grid feat-grid-1">
            <div class="feat-btn" id="${ID}-fan-talk-dialogue">对白增多</div>
          </div>
          <div class="sexy-group" id="${ID}-robtalk-group">
            <div class="sexy-seg" id="${ID}-item-robtalk-n">
              <div class="sexy-seg-label">可抢话</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-robtalk-h">
              <div class="sexy-seg-label">话痨抢话</div>
            </div>
          </div>
          <div class="sexy-title">不抢话设置</div>
          <div class="sexy-group" id="${ID}-talk-group">
            <div class="sexy-seg" id="${ID}-item-talk-l">
              <div class="sexy-seg-label">轻度</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-talk-m">
              <div class="sexy-seg-label">中度</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-talk-h">
              <div class="sexy-seg-label">重度</div>
            </div>
          </div>
          <div class="sexy-group" id="${ID}-word-group">
            <div class="sexy-seg" id="${ID}-item-word-s">
              <div class="sexy-seg-label">少字数</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-word-m">
              <div class="sexy-seg-label">中字数</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-word-l">
              <div class="sexy-seg-label">多字数</div>
            </div>
          </div>
          <div class="sexy-title">人称设置</div>
          <div class="sexy-group">
            <div class="sexy-seg" id="${ID}-item-pov-1">
              <div class="sexy-seg-label">第一人称</div>
              <div class="sexy-seg-desc">我/我的</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-pov-2">
              <div class="sexy-seg-label">第二人称</div>
              <div class="sexy-seg-desc">你/你的</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-pov-3">
              <div class="sexy-seg-label">第三人称</div>
              <div class="sexy-seg-desc">他/她/它</div>
            </div>
          </div>
          <div class="sexy-title">转述与否</div>
          <div class="sexy-group" id="${ID}-paraphrase-group">
            <div class="sexy-seg" id="${ID}-item-para-yes">
              <div class="sexy-seg-label">转述</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-para-no">
              <div class="sexy-seg-label">不转述</div>
            </div>
          </div>
          <div class="sexy-title">预设功能</div>
          <div class="feat-grid feat-grid-3">
            <div class="feat-btn" id="${ID}-feat-0">防全知</div>
            <div class="feat-btn" id="${ID}-feat-1">读世界书</div>
            <div class="feat-btn" id="${ID}-feat-2">防变量出错</div>
            <div class="feat-btn" id="${ID}-feat-3">防媚user</div>
            <div class="feat-btn" id="${ID}-feat-4">边写边思考</div>
            <div class="feat-btn" id="${ID}-feat-5">剧情审视</div>
            <div class="feat-btn" id="${ID}-feat-6">活人感</div>
          </div>
          <div class="sexy-title">剧情推进速度</div>
          <div class="sexy-group">
            <div class="sexy-seg" id="${ID}-item-pace-0">
              <div class="sexy-seg-label pace-label">超级<br>快进</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-pace-1">
              <div class="sexy-seg-label pace-label">快速</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-pace-2">
              <div class="sexy-seg-label pace-label">正常</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-pace-3">
              <div class="sexy-seg-label pace-label">慢速</div>
            </div>
          </div>

          <div class="sexy-title">粉丝定制功能</div>
          <div class="feat-grid feat-grid-2">
            <div class="feat-btn" id="${ID}-fan-0">行动选项</div>
            <div class="feat-btn" id="${ID}-fan-1">npc有内心独白</div>
          </div>
          <div class="feat-grid feat-grid-2">
            <div class="feat-btn" id="${ID}-fan-mimi">咪咪吐槽</div>
            <div class="feat-btn" id="${ID}-fan-2">显示时间地点</div>
          </div>
          <div class="feat-grid feat-grid-2">
            <div class="feat-btn" id="${ID}-fan-3">剧情推动引擎</div>
            <div class="feat-btn" id="${ID}-fan-4">性爱场景特写</div>
          </div>
          <div class="sexy-title">切换模式</div>
          <div class="feat-grid feat-grid-2">
